+    "action": {
       "type": "string",
-      "enum": ["show", "init", "get", "set", "validate", "migrate", "edit"],
-      "description": "Config subcommand that was executed"
-    },
-    "config_dir": {
-      "type": "string",
-      "description": "Configuration directory path"
+      "enum": ["show", "get", "set", "init", "validate", "migrate", "edit"],
+      "description": "Config subcommand"
     },
     "config_file": {
       "type": "string",
