+      "description": "Config value"
     },
-    "initialized": {
+    "valid": {
       "type": "boolean",
-      "description": "Whether config was initialized (for init)"
+      "description": "Validation result"
     },
-    "files_created": {
+    "errors": {
       "type": "array",
-      "items": { "type": "string" },
